import React, { useState } from "react";

export default function AddTask({ onTaskAdded }) {
  const [formData, setFormData] = useState({
    title: "",
    dueDate: "",
    priority: "MEDIUM",
    category: "",
    completed: false,
  });

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData({
      ...formData,
      [name]: type === "checkbox" ? checked : value,
    });
  };

  const handleAdd = async (e) => {
    e.preventDefault();

    if (!formData.title || !formData.dueDate) {
      alert("Fill required fields");
      return;
    }

    try {
      const res = await fetch("http://localhost:8086/tasks", {
        method: "POST",
        headers: {"Content-Type": "application/json"},
        body: JSON.stringify({
          ...formData,
          autoGenerated: false,
          suggestionSource: null,
          notified: false
        })
      });

      if (res.ok) {
        setFormData({
          title: "",
          dueDate: "",
          priority: "MEDIUM",
          category: "",
          completed: false,
        });
        if (onTaskAdded) onTaskAdded();
      }
    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div className="bg-gray-100 min-h-screen p-6">

      {/* Card Container */}
      <div className="max-w-3xl mx-auto rounded-2xl shadow-lg overflow-hidden bg-white">

        {/* Header */}
        <div className="bg-blue-900 text-white px-6 py-5 flex justify-between items-center">
          <div>
            <h2 className="text-2xl font-bold">Add Task</h2>
            <p className="text-sm text-blue-200">Manage your daily work</p>
          </div>
        </div>

        {/* Form */}
        <form onSubmit={handleAdd} className="p-6 space-y-5">

          {/* Title */}
          <input
            type="text"
            name="title"
            value={formData.title}
            onChange={handleChange}
            placeholder="Enter task title"
            className="w-full px-4 py-3 rounded-xl border border-gray-300 focus:ring-2 focus:ring-blue-400 outline-none"
            required
          />

          {/* Row */}
          <div className="grid md:grid-cols-2 gap-4">

            {/* Date */}
            <input
              type="date"
              name="dueDate"
              value={formData.dueDate}
              onChange={handleChange}
              className="px-4 py-3 rounded-xl border border-gray-300 focus:ring-2 focus:ring-blue-400 outline-none"
              required
            />

            {/* Priority */}
            <select
              name="priority"
              value={formData.priority}
              onChange={handleChange}
              className="px-4 py-3 rounded-xl border border-gray-300 focus:ring-2 focus:ring-blue-400 outline-none"
            >
              <option value="LOW">Low Priority</option>
              <option value="MEDIUM">Medium Priority</option>
              <option value="HIGH">High Priority</option>
            </select>
          </div>

          {/* Category */}
          <input
            type="text"
            name="category"
            value={formData.category}
            onChange={handleChange}
            placeholder="Category (Study, Work...)"
            className="w-full px-4 py-3 rounded-xl border border-gray-300 focus:ring-2 focus:ring-blue-400 outline-none"
          />

          {/* Checkbox */}
          <label className="flex items-center gap-3 text-gray-700">
            <input
              type="checkbox"
              name="completed"
              checked={formData.completed}
              onChange={handleChange}
              className="w-5 h-5 accent-blue-600"
            />
            Mark as Completed
          </label>

          {/* Button */}
          <button
            type="submit"
            className="w-full bg-blue-900 text-white py-3 rounded-xl font-semibold hover:bg-blue-800 transition"
          >
            Add Task
          </button>
        </form>
      </div>
    </div>
  );
}
